import { getTransactions } from './getTransactions.js';
export async function getTradeHistory(params) {
    const { address, marketAddress, ...rest } = params;
    const result = await getTransactions({
        address,
        marketAddress,
        ...rest,
    });
    return {
        address,
        marketAddress,
        transactions: result.transactions,
        total: result.total,
    };
}
